import { InventoryItem } from './inventory';
import { GameEvent } from './events';
import { ShopCustomer } from './shop';
import { Mercenary } from '../models/Mercenary';
import { Expedition } from '../models/Dungeon';

export type RoomType = 'EMPTY' | 'ENTRANCE' | 'BOSS' | 'KEY' | 'WALL' | 'NPC' | 'GOLD' | 'TRAP';

export interface ManualDungeonSession {
    dungeonId: string;
    partyIds: string[];
    grid: RoomType[][];
    visited: boolean[][]; // Fog of war
    playerPos: { x: number, y: number };
    hasKey: boolean;
    isBossLocked: boolean;
    isBossDefeated?: boolean; // New: Tracks if boss was beaten but player is still inside
    npcFound?: boolean; // Track if the NPC in this session was interacted with
    rescuedNpcId?: string; // ID of the NPC rescued during this session
    goldCollected: number; // Cumulative gold found during this session
}

export interface DailyFinancials {
  incomeShop: number;
  incomeInventory: number;
  incomeDungeon: number;
  incomeRepair: number;
  expenseMarket: number;
  expenseWages: number;
  expenseScout: number;
}

export interface PlayerStats {
  gold: number;
  energy: number;
  maxEnergy: number;
  day: number;
  tierLevel: number; // Current crafting/market tier access
  dailyFinancials: DailyFinancials; // Track detailed financial history for the current day
}

export interface ForgeStatus {
  hasFurnace: boolean;
  hasWorkbench: boolean;
  anvilLevel: number;
  isShopOpen: boolean;
}

export interface DungeonResult {
    dungeonName: string;
    rewards: { id: string; name: string; count: number }[];
    goldGained?: number;
    mercenaryResults: {
        id: string;
        name: string;
        job: string;
        levelBefore: number;
        levelAfter: number;
        xpGained: number;
        currentXp: number;
        xpToNext: number;
    }[];
    rescuedMercenary?: Mercenary; // Rescued NPC to be displayed in the result
}

export interface GameToast {
    message: string;
    visible: boolean;
}

export interface GameState {
  stats: PlayerStats;
  inventory: InventoryItem[];
  forge: ForgeStatus;
  activeEvent: GameEvent | null;
  logs: string[]; // For showing history of actions
  knownMercenaries: Mercenary[]; // Tracked regulars and named NPCs

  // Shop System State
  activeCustomer: ShopCustomer | null; // The person currently at the counter
  shopQueue: ShopCustomer[]; // People waiting in line
  visitorsToday: string[]; // List of Mercenary IDs who have visited today
  talkedToToday: string[]; // List of Mercenary IDs who have been talked to today for affinity bonus

  // Market State
  marketStock: Record<string, number>; // Remaining quantity per item ID

  // Game Logic Control
  isCrafting: boolean; // Is the player currently in the minigame?
  showSleepModal: boolean; // Should the End of Day modal be visible?
  showJournal: boolean; // Toggle for the Log/Journal Modal
  toast: GameToast | null; // Global toast notifications

  // Progression
  craftingMastery: Record<string, number>; // Key: Item ID, Value: Craft Count
  unlockedRecipes: string[]; // List of IDs for recipes discovered via gameplay
  unlockedTabs: string[]; // List of unlocked Tab IDs (e.g. 'FORGE', 'MARKET', 'SHOP')

  // Minigame Persistence
  forgeTemperature: number; // Residual heat from last session
  lastForgeTime: number; // Timestamp of last minigame interaction

  // Dungeon System
  activeExpeditions: Expedition[];
  dungeonClearCounts: Record<string, number>; // Key: Dungeon ID, Value: Count
  dungeonResult: DungeonResult | null; // Populated when claim is clicked to show modal
  activeManualDungeon: ManualDungeonSession | null; // Current manual play session
  showManualDungeonOverlay: boolean; // Toggle for dungeon UI visibility

  // Result Tracking
  lastCraftedItem: InventoryItem | null;

  // UI Effects State
  uiEffects: {
    energyHighlight: boolean;
  };
}

import { GameState, InventoryItem } from '../types/index';
import { NAMED_MERCENARIES } from '../data/mercenaries';
import { MATERIALS } from '../data/materials';
import { MARKET_CATALOG } from '../data/market/index';
import { DUNGEON_CONFIG } from '../config/dungeon-config';

const createInitialInventory = (): InventoryItem[] => [
    { ...MATERIALS.ANVIL, type: 'TOOL', quantity: 1 },
    { ...MATERIALS.HAMMER, type: 'TOOL', quantity: 1 },
    // Starter Materials
    { ...MATERIALS.CHARCOAL, quantity: 5 },
    { ...MATERIALS.COPPER_ORE, quantity: 2 },
    { ...MATERIALS.TIN_ORE, quantity: 1 },
    { ...MATERIALS.OAK_LOG, quantity: 1 },
    { ...MATERIALS.EMERGENCY_GOLD, quantity: 1 },
];

export const createInitialGameState = (): GameState => ({
    stats: {
        gold: 1500,
        energy: 100,
        maxEnergy: 100,
        day: 1,
        tierLevel: 0,
        dailyFinancials: {
            incomeShop: 0,
            incomeInventory: 0,
            incomeDungeon: 0,
            incomeRepair: 0,
            expenseMarket: 0,
            expenseWages: 0,
            expenseScout: 0
        },
    },
    inventory: createInitialInventory(),
    forge: {
        hasFurnace: false,
        hasWorkbench: false,
        anvilLevel: 1,
        isShopOpen: false,
    },
    activeEvent: null,
    logs: ['You stand amidst the ruins of Lockhart\'s Forge.', 'The equipment is cold and broken. You need to gather gold to rebuild.'],
    knownMercenaries: [...NAMED_MERCENARIES].map(m => ({
        ...m,
        expeditionEnergy: DUNGEON_CONFIG.MAX_EXPEDITION_ENERGY,
        currentXp: 0,
        xpToNextLevel: m.level * 100,
        status: 'VISITOR'
    })),

    // Shop State
    activeCustomer: null,
    shopQueue: [],
    visitorsToday: [],
    talkedToToday: [],

    // Market Initial Stock
    marketStock: MARKET_CATALOG.reduce((acc, item) => ({ ...acc, [item.id]: item.maxStock }), {}),

    // Game Logic State
    isCrafting: false,
    showSleepModal: false,
    showJournal: false,
    toast: null,

    // Progression
    craftingMastery: {},
    unlockedRecipes: [],
    unlockedTabs: ['FORGE', 'MARKET'],

    // Minigame Persistence
    forgeTemperature: 0,
    lastForgeTime: 0,

    // Dungeon System
    activeExpeditions: [],
    dungeonClearCounts: {},
    dungeonResult: null,
    activeManualDungeon: null,
    showManualDungeonOverlay: false,

    // Result Tracking
    lastCraftedItem: null,

    // UI Effects State
    uiEffects: {
        energyHighlight: false
    }
});

import React, { useState, useRef, useEffect, useCallback, useLayoutEffect } from 'react';
import Header from './Header';
import { InventoryDisplay } from './InventoryDisplay';
import { Anvil, Package, ShoppingBag, Coins, Beer, Map as MapIcon, Activity, Info, ChevronLeft, ChevronRight } from 'lucide-react';
import { useGame } from '../context/GameContext';

// Import Background Services
import { useShopService } from '../services/shop/shop-service';
import { useDungeonService } from '../services/dungeon/dungeon-service';

// Import Tabs
import ForgeTab from './tabs/Forge/ForgeTab';
import ShopTab from './tabs/Shop/ShopTab';
import TavernTab from './tabs/Tavern/TavernTab';
import MarketTab from './tabs/Market/MarketTab';
import DungeonTab from './tabs/Dungeon/DungeonTab';
import SimulationTab from './tabs/Simulation/SimulationTab';

// Import Modals
import EventModal from './modals/EventModal';
import SleepModal from './modals/SleepModal';
import JournalModal from './modals/JournalModal';
import DungeonResultModal from './modals/DungeonResultModal';
import CraftingResultModal from './modals/CraftingResultModal';
import SettingsModal from './modals/SettingsModal';

interface MainGameLayoutProps {
    onQuit: () => void;
    onLoadFromSettings: (data: any, index: number) => void;
}

const MainGameLayout: React.FC<MainGameLayoutProps> = ({ onQuit, onLoadFromSettings }) => {
  const [activeTab, setActiveTab] = useState<'FORGE' | 'INVENTORY' | 'MARKET' | 'SHOP' | 'TAVERN' | 'DUNGEON' | 'SIMULATION'>('FORGE');
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const { state, actions } = useGame();

  // Scroll visibility logic
  const scrollRef = useRef<HTMLDivElement>(null);
  const [showLeftArrow, setShowLeftArrow] = useState(false);
  const [showRightArrow, setShowRightArrow] = useState(false);

  const updateArrows = useCallback(() => {
    if (scrollRef.current) {
      const { scrollLeft, scrollWidth, clientWidth } = scrollRef.current;

      // 스크롤이 가능한 상태인지 체크
      const canScroll = scrollWidth > clientWidth + 2;

      // 왼쪽 끝 감지: scrollLeft가 1 이하이면 완전히 숨김
      setShowLeftArrow(canScroll && scrollLeft > 1);

      // 오른쪽 끝 감지: Math.ceil을 사용하여 소수점 픽셀 오차 보정
      const isAtEnd = Math.ceil(scrollLeft) >= (scrollWidth - clientWidth - 2);
      setShowRightArrow(canScroll && !isAtEnd);
    }
  }, []);

  const scrollTabs = (direction: 'LEFT' | 'RIGHT') => {
    if (scrollRef.current) {
      const amount = direction === 'LEFT' ? -200 : 200;
      scrollRef.current.scrollBy({ left: amount, behavior: 'smooth' });
    }
  };

  useLayoutEffect(() => {
    // 렌더링 직후 여백을 계산하여 버튼 가시성 설정
    const timer = setTimeout(updateArrows, 100);
    return () => clearTimeout(timer);
  }, [updateArrows, activeTab]);

  useEffect(() => {
    window.addEventListener('resize', updateArrows);
    return () => window.removeEventListener('resize', updateArrows);
  }, [updateArrows]);

  // --- BACKGROUND SERVICES ---
  useShopService();
  useDungeonService();

  const completedExpeditionsCount = state.activeExpeditions.filter(
      exp => exp.status === 'COMPLETED'
  ).length;

  const totalShopVisitors = (state.activeCustomer ? 1 : 0) + state.shopQueue.length;

  const isFullscreenOverlay = state.isCrafting || (state.activeManualDungeon && state.showManualDungeonOverlay);

  // Tab Button Helper
  const renderTabButton = (id: typeof activeTab, Icon: any, label: string, badgeCount: number = 0) => {
    const isActive = activeTab === id;
    return (
        <button 
            onClick={() => setActiveTab(id)}
            className={`relative flex items-center gap-2 px-5 md:px-6 py-3 md:py-4 border-b-2 transition-all whitespace-nowrap snap-start shrink-0 ${
                isActive 
                ? 'border-amber-500 text-amber-500 bg-stone-800/60 z-10' 
                : 'border-transparent text-stone-500 hover:text-stone-300 hover:bg-stone-800/30'
            }`}
        >
            <Icon className={`w-4 h-4 md:w-5 md:h-5 ${isActive ? 'scale-110' : ''}`} />
            <span className="font-bold tracking-wide text-[10px] md:text-sm uppercase">{label}</span>
            {badgeCount > 0 && (
                <div className="absolute top-1 right-1 flex h-4 w-4 md:h-5 md:w-5 items-center justify-center rounded-full bg-red-600 text-[8px] md:text-[10px] font-black text-white shadow-lg ring-2 ring-stone-900 animate-in zoom-in">
                    {badgeCount}
                </div>
            )}
        </button>
    );
  };

  const availableTabs = [
    { id: 'FORGE' as const, icon: Anvil, label: 'Forge' },
    { id: 'DUNGEON' as const, icon: MapIcon, label: 'Dungeon', badge: completedExpeditionsCount },
    { id: 'INVENTORY' as const, icon: Package, label: 'Items' },
    { id: 'MARKET' as const, icon: ShoppingBag, label: 'Market' },
    { id: 'SHOP' as const, icon: Coins, label: 'Shop', badge: activeTab !== 'SHOP' ? totalShopVisitors : 0 },
    { id: 'TAVERN' as const, icon: Beer, label: 'Tavern' },
    { id: 'SIMULATION' as const, icon: Activity, label: 'Sim' },
  ].filter(tab => state.unlockedTabs.includes(tab.id));

  return (
    <div className="h-[100dvh] w-full bg-stone-950 text-stone-200 flex flex-col overflow-hidden font-sans selection:bg-amber-500/30 animate-in fade-in duration-500 px-safe">

      {/* Top Section Wrapper */}
      <div className={`flex flex-col shrink-0 z-30 transition-all duration-500 ease-in-out ${isFullscreenOverlay ? '-translate-y-full h-0 opacity-0 pointer-events-none' : 'translate-y-0 h-auto opacity-100'}`}>
        <Header 
          activeTab={activeTab} 
          onTabChange={setActiveTab} 
          onSettingsClick={() => setIsSettingsOpen(true)}
        />

        {/* Tab Navigation Wrapper - isolate to prevent stacking issues */}
        <div className="bg-stone-900 border-b border-stone-800 flex items-center relative z-10 overflow-hidden isolate h-11 md:h-14">

          {/* Left Mask & Arrow - Completely scale out and hide if at start */}
          <div 
            className={`absolute left-0 top-0 bottom-0 z-30 w-12 flex items-center transition-all duration-300 transform-gpu ${
                showLeftArrow ? 'opacity-100 scale-100 visible pointer-events-auto' : 'opacity-0 scale-0 invisible pointer-events-none'
            }`}
          >
              <div className="absolute inset-0 bg-gradient-to-r from-stone-900 via-stone-900/90 to-transparent" />
              <button 
                onClick={() => scrollTabs('LEFT')}
                className="relative h-full w-full flex items-center pl-2 group/arrow"
                aria-label="Scroll Left"
              >
                <ChevronLeft className="w-5 h-5 text-amber-500 group-hover:scale-125 transition-transform drop-shadow-[0_0_8px_rgba(245,158,11,0.5)]" />
              </button>
          </div>

          {/* Scrollable Container - Removed inner padding div to allow scrollLeft 0 to be absolute start */}
          <div 
            ref={scrollRef}
            onScroll={updateArrows}
            className="flex overflow-x-auto no-scrollbar flex-1 min-w-0 touch-pan-x scroll-smooth snap-x snap-mandatory overscroll-behavior-x-contain"
            style={{ WebkitOverflowScrolling: 'touch' }}
          >
            {availableTabs.map(tab => renderTabButton(tab.id, tab.icon, tab.label, tab.badge))}
          </div>

          {/* Right Mask & Arrow - Completely scale out and hide if at end */}
          <div 
            className={`absolute right-0 top-0 bottom-0 z-30 w-12 flex items-center justify-end transition-all duration-300 transform-gpu ${
                showRightArrow ? 'opacity-100 scale-100 visible pointer-events-auto' : 'opacity-0 scale-0 invisible pointer-events-none'
            }`}
          >
              <div className="absolute inset-0 bg-gradient-to-l from-stone-900 via-stone-900/90 to-transparent" />
              <button 
                onClick={() => scrollTabs('RIGHT')}
                className="relative h-full w-full flex items-center justify-end pr-2 group/arrow"
                aria-label="Scroll Right"
              >
                <ChevronRight className="w-5 h-5 text-amber-500 group-hover:scale-125 transition-transform drop-shadow-[0_0_8px_rgba(245,158,11,0.5)]" />
              </button>
          </div>
        </div>
      </div>

      <main className="flex-1 overflow-hidden relative bg-stone-925 flex flex-col min-h-0">
        <div className={`h-full w-full ${activeTab === 'FORGE' ? 'block' : 'hidden'}`}>
            <ForgeTab onNavigate={setActiveTab} />
        </div>
        <div className={`h-full w-full ${activeTab === 'SHOP' ? 'block' : 'hidden'}`}>
            <ShopTab onNavigate={setActiveTab} />
        </div>
        {activeTab === 'INVENTORY' && <InventoryDisplay />}
        {activeTab === 'MARKET' && <MarketTab onNavigate={setActiveTab} />}
        {activeTab === 'TAVERN' && <TavernTab />}
        {activeTab === 'DUNGEON' && <DungeonTab />}
        {activeTab === 'SIMULATION' && <SimulationTab />}
      </main>

      {/* Toast Notification Container */}
      {state.toast?.visible && (
        <div 
            onClick={actions.hideToast}
            className="fixed bottom-8 left-1/2 -translate-x-1/2 z-[3000] flex items-center gap-3 px-6 py-3 bg-stone-900/95 border border-amber-500/50 text-stone-200 rounded-xl shadow-2xl backdrop-blur-md cursor-pointer animate-in slide-in-from-bottom-4 fade-in duration-300 ring-2 ring-black/50 active:scale-95 w-max max-w-[80vw]"
        >
            <Info className="w-5 h-5 text-amber-500 shrink-0" />
            <span className="text-sm font-bold tracking-tight text-center leading-tight">{state.toast.message}</span>
        </div>
      )}

      {/* Navigation Padding */}
      <div className="h-[env(safe-area-inset-bottom)] bg-stone-900 shrink-0"></div>

      <EventModal />
      <SleepModal />
      <JournalModal />
      <DungeonResultModal />
      <CraftingResultModal />
      <SettingsModal 
        isOpen={isSettingsOpen} 
        onClose={() => setIsSettingsOpen(false)} 
        onQuit={onQuit} 
        onLoadRequest={onLoadFromSettings}
      />
    </div>
  );
};

export default MainGameLayout;

import { GameState, InventoryItem } from '../../types/index';
import { MATERIALS } from '../../data/materials';
import { Mercenary } from '../../models/Mercenary';
import { DUNGEON_CONFIG } from '../../config/dungeon-config';

export const handleAcquireItem = (state: GameState, payload: { id: string; quantity: number }): GameState => {
    const { id, quantity } = payload;
    const itemDef = Object.values(MATERIALS).find(i => i.id === id);
    if (!itemDef) return state;

    const existingItem = state.inventory.find(i => i.id === id);
    const newInventory = existingItem
    ? state.inventory.map(i => i.id === id ? { ...i, quantity: i.quantity + quantity } : i)
    : [...state.inventory, { ...itemDef, quantity } as InventoryItem];

    return {
    ...state,
    inventory: newInventory,
    logs: [`Acquired ${itemDef.name} x${quantity}.`, ...state.logs],
    };
};

export const handlePayCost = (state: GameState, payload: { gold?: number; items?: { id: string; count: number }[] }): GameState => {
    const { gold, items } = payload;
    let newGold = state.stats.gold;
    let newInventory = [...state.inventory];

    if (gold) newGold -= gold;
    if (items) {
        items.forEach(costItem => {
            newInventory = newInventory.map(invItem => {
                if (invItem.id === costItem.id) {
                    return { ...invItem, quantity: invItem.quantity - costItem.count };
                }
                return invItem;
            }).filter(i => i.quantity > 0);
        });
    }
    return {
        ...state,
        stats: { ...state.stats, gold: newGold },
        inventory: newInventory
    };
};

export const handleBuyMarketItems = (state: GameState, payload: { items: { id: string; count: number }[]; totalCost: number }): GameState => {
    const { items, totalCost } = payload;

    const newGold = state.stats.gold - totalCost;
    if (newGold < 0) return state; 

    let newInventory = [...state.inventory];
    let newTierLevel = state.stats.tierLevel;
    let newForgeState = { ...state.forge };
    let logUpdates: string[] = [`Bought supplies for ${totalCost} Gold.`];
    let newMarketStock = { ...state.marketStock };
    let newUnlockedTabs = [...state.unlockedTabs];

    if (!newUnlockedTabs.includes('INVENTORY')) {
        newUnlockedTabs.push('INVENTORY');
        logUpdates.unshift("Access granted: Inventory facility is now operational.");
    }

    items.forEach(buyItem => {
            // Update stock
            newMarketStock[buyItem.id] = Math.max(0, (newMarketStock[buyItem.id] || 0) - buyItem.count);

            if (buyItem.id === 'scroll_t2') {
                newTierLevel = Math.max(newTierLevel, 2);
                logUpdates.unshift('Upgrade Complete: Market Tier 2 Unlocked!');
                return; 
            }
            if (buyItem.id === 'scroll_t3') {
                newTierLevel = Math.max(newTierLevel, 3);
                logUpdates.unshift('Upgrade Complete: Market Tier 3 Unlocked!');
                return; 
            }
            if (buyItem.id === 'furnace') {
                newForgeState.hasFurnace = true;
                if (newTierLevel === 0) newTierLevel = 1; 
                logUpdates.unshift('Furnace acquired! You can now start forging metal.');

                if (!newUnlockedTabs.includes('SHOP')) {
                    newUnlockedTabs.push('SHOP');
                    logUpdates.unshift("Facility restored: The Shop Counter is now available.");
                }
                if (!newUnlockedTabs.includes('SIMULATION')) {
                    newUnlockedTabs.push('SIMULATION');
                }

                return; 
            }
            if (buyItem.id === 'workbench') {
                newForgeState.hasWorkbench = true;
                logUpdates.unshift('Workbench installed! You can now craft leather and wood equipment.');
                return;
            }
            const itemDef = Object.values(MATERIALS).find(i => i.id === buyItem.id);
            if (itemDef) {
                const existingItem = newInventory.find(i => i.id === buyItem.id);
                if (existingItem) {
                    newInventory = newInventory.map(i => i.id === buyItem.id ? { ...i, quantity: i.quantity + buyItem.count } : i);
                } else {
                    newInventory.push({ ...itemDef, quantity: buyItem.count } as InventoryItem);
                }
            }
    });

    return {
        ...state,
        stats: { 
            ...state.stats, 
            gold: newGold, 
            tierLevel: newTierLevel,
            dailyFinancials: {
                ...state.stats.dailyFinancials,
                expenseMarket: state.stats.dailyFinancials.expenseMarket + totalCost
            }
        },
        forge: newForgeState,
        inventory: newInventory,
        marketStock: newMarketStock,
        unlockedTabs: newUnlockedTabs,
        logs: [...logUpdates, ...state.logs]
    };
};

export const handleInstallFurnace = (state: GameState): GameState => {
    let newUnlockedTabs = [...state.unlockedTabs];
    if (!newUnlockedTabs.includes('SHOP')) newUnlockedTabs.push('SHOP');

    return {
        ...state,
        forge: { ...state.forge, hasFurnace: true },
        unlockedTabs: newUnlockedTabs,
        logs: ['The Furnace has been installed! The forge comes alive.', ...state.logs]
    };
};

export const handleSellItem = (state: GameState, payload: { itemId: string; count: number; price: number; equipmentInstanceId?: string; customer?: Mercenary }): GameState => {
    const { itemId, count, price, equipmentInstanceId, customer } = payload;

    let newInventory = [...state.inventory];
    let itemName = 'Item';
    let newKnownMercenaries = [...state.knownMercenaries];
    let logMessage = '';
    let newActiveCustomer = state.activeCustomer;

    const isShopSale = !!customer;

    if (equipmentInstanceId) {
        const itemIndex = newInventory.findIndex(i => i.id === equipmentInstanceId);
        if (itemIndex > -1) {
            itemName = newInventory[itemIndex].name;
            newInventory.splice(itemIndex, 1);
        }
    } else {
        newInventory = newInventory.map(item => {
            if (item.id === itemId) {
                itemName = item.name;
                return { ...item, quantity: item.quantity - count };
            }
            return item;
        }).filter(i => i.quantity > 0);
    }

    if (customer) {
        const existingMercIdx = newKnownMercenaries.findIndex(m => m.id === customer.id);

        if (existingMercIdx > -1) {
            const merc = { ...newKnownMercenaries[existingMercIdx] };
            merc.affinity = Math.min(100, (merc.affinity || 0) + 2); 
            merc.visitCount = (merc.visitCount || 0) + 1;
            merc.lastVisitDay = state.stats.day;
            newKnownMercenaries[existingMercIdx] = merc;
            logMessage = `Sold ${itemName} to ${customer.name}. Affinity rose to ${merc.affinity}.`;
        } else {
            const newMerc: Mercenary = {
                ...customer,
                affinity: 2,
                visitCount: 1,
                lastVisitDay: state.stats.day,
                expeditionEnergy: DUNGEON_CONFIG.MAX_EXPEDITION_ENERGY,
                currentXp: 0,
                xpToNextLevel: 100,
                status: 'VISITOR' // Explicitly set status to VISITOR for new contacts
            };
            newKnownMercenaries.push(newMerc);
            logMessage = `Sold ${itemName} to ${customer.name}. (New Contact)`;
        }

        if (state.activeCustomer && state.activeCustomer.mercenary.id === customer.id) {
            newActiveCustomer = null; 
        }
    } else {
        logMessage = `Sold ${itemName} for ${price} Gold.`;
    }

    return {
        ...state,
        inventory: newInventory,
        stats: { 
            ...state.stats, 
            gold: state.stats.gold + price,
            dailyFinancials: {
                ...state.stats.dailyFinancials,
                incomeShop: state.stats.dailyFinancials.incomeShop + (isShopSale ? price : 0),
                incomeInventory: state.stats.dailyFinancials.incomeInventory + (!isShopSale ? price : 0)
            }
        },
        knownMercenaries: newKnownMercenaries,
        activeCustomer: newActiveCustomer,
        logs: [logMessage, ...state.logs]
    };
};

export const handleUseItem = (state: GameState, payload: { itemId: string }): GameState => {
    const { itemId } = payload;
    const inventoryItem = state.inventory.find(i => i.id === itemId);

    if (!inventoryItem || inventoryItem.quantity <= 0) return state;

    let newStats = { ...state.stats };
    let newUnlockedRecipes = [...(state.unlockedRecipes || [])];
    let logMsg = '';
    let itemUsed = false;

    // Logic per Item ID
    if (itemId === 'energy_potion') {
        const recoverAmount = 25;
        if (newStats.energy >= newStats.maxEnergy) {
            return {
                ...state,
                logs: [`Energy is already full!`, ...state.logs]
            };
        }
        newStats.energy = Math.min(newStats.maxEnergy, newStats.energy + recoverAmount);
        logMsg = `Consumed Energy Potion. +${recoverAmount} Energy.`;
        itemUsed = true;
    } 
    else if (itemId === 'recipe_scroll_bronze_longsword') {
        const targetRecipeId = 'sword_bronze_long_t1';
        if (newUnlockedRecipes.includes(targetRecipeId)) {
            return {
                ...state,
                logs: [`You already know the techniques in this scroll.`, ...state.logs]
            };
        }
        newUnlockedRecipes.push(targetRecipeId);
        logMsg = `Studied the scroll. Bronze Longsword recipe unlocked!`;
        itemUsed = true;
    }

    if (!itemUsed) return state;

    // Deduct Item
    const newInventory = state.inventory.map(item => {
        if (item.id === itemId) {
            return { ...item, quantity: item.quantity - 1 };
        }
        return item;
    }).filter(i => i.quantity > 0);

    return {
        ...state,
        stats: newStats,
        inventory: newInventory,
        unlockedRecipes: newUnlockedRecipes,
        logs: [logMsg, ...state.logs]
    };
};

import { GameState } from '../../types/index';
import { GAME_CONFIG } from '../../config/game-config';

export const handleRepairWork = (state: GameState): GameState => {
  if (state.stats.energy < GAME_CONFIG.ENERGY_COST.REPAIR) return state;

  const earn = 15;
  let newUnlockedTabs = [...state.unlockedTabs];
  let logPrefix = "";

  if (!newUnlockedTabs.includes('INVENTORY')) {
    newUnlockedTabs.push('INVENTORY');
    logPrefix = "Facility restored: Inventory tracking is now active. ";
  }

  return {
    ...state,
    stats: { 
      ...state.stats, 
      energy: state.stats.energy - GAME_CONFIG.ENERGY_COST.REPAIR,
      gold: state.stats.gold + earn,
      dailyFinancials: {
          ...state.stats.dailyFinancials,
          incomeRepair: state.stats.dailyFinancials.incomeRepair + earn
      }
    },
    unlockedTabs: newUnlockedTabs,
    logs: [`${logPrefix}Performed cold repairs for a neighbor. Gold +${earn}. Energy -${GAME_CONFIG.ENERGY_COST.REPAIR}.`, ...state.logs],
  };
};

import { GameState } from '../../types/index';
import { calculateDailyWage } from '../../config/contract-config';
import { DUNGEON_CONFIG } from '../../config/dungeon-config';
import { MARKET_CATALOG } from '../../data/market/index';

export const handleSleep = (state: GameState): GameState => {
    return { ...state, showSleepModal: true };
};

export const handleConfirmSleep = (state: GameState): GameState => {
    // Calculate wages for HIRED, ON_EXPEDITION, INJURED mercenaries
    const hiredMercs = state.knownMercenaries.filter(m => 
        ['HIRED', 'ON_EXPEDITION', 'INJURED'].includes(m.status)
    );
    let totalWages = 0;
    hiredMercs.forEach(merc => {
        totalWages += calculateDailyWage(merc.level, merc.job);
    });

    const nextDay = state.stats.day + 1;
    const newGold = state.stats.gold - totalWages;

    // --- Mercenary Energy Recovery ---
    const updatedMercenaries = state.knownMercenaries.map(merc => {
        if (['HIRED', 'INJURED', 'VISITOR'].includes(merc.status)) { // Only recover if not on expedition
            return {
                ...merc,
                expeditionEnergy: Math.min(DUNGEON_CONFIG.MAX_EXPEDITION_ENERGY, (merc.expeditionEnergy || 0) + DUNGEON_CONFIG.DAILY_ENERGY_RECOVERY)
            };
        }
        return merc;
    });

    // --- Market Restock Logic ---
    const newMarketStock = { ...state.marketStock };
    MARKET_CATALOG.forEach(item => {
        const isOneTime = item.id === 'furnace' || item.id === 'workbench' || item.id.startsWith('scroll_');

        if (isOneTime) {
            // 일회성 아이템은 이미 소유했거나 해당 티어보다 높은 경우 리스톡하지 않음 (0 유지)
            const isOwnedOrUnlocked = 
                (item.id === 'furnace' && state.forge.hasFurnace) || 
                (item.id === 'workbench' && state.forge.hasWorkbench) ||
                (item.id === 'scroll_t2' && state.stats.tierLevel >= 2) ||
                (item.id === 'scroll_t3' && state.stats.tierLevel >= 3);

            if (isOwnedOrUnlocked) {
                newMarketStock[item.id] = 0;
            } else {
                newMarketStock[item.id] = item.maxStock;
            }
        } else {
            // 일반 자원 및 소모품은 매일 다시 채움
            newMarketStock[item.id] = item.maxStock;
        }
    });

    let newUnlockedTabs = [...state.unlockedTabs];
    let logMsg = `Day ${nextDay} begins. Market supplies restocked. (Auto-saved)`;

    if (nextDay === 2 && !newUnlockedTabs.includes('TAVERN')) {
        newUnlockedTabs.push('TAVERN');
        logMsg = `Day 2 begins. Travelers are gathering at the Tavern. Facility Unlocked! (Auto-saved)`;
    }

    if (totalWages > 0) logMsg = `Day ${nextDay} begins. Paid ${totalWages} G in wages. (Auto-saved)`;
    if (newGold < 0) logMsg = `Day ${nextDay} begins. You are in debt! (${newGold} G). (Auto-saved)`;

    return {
        ...state,
        stats: {
            ...state.stats,
            day: nextDay,
            gold: newGold,
            energy: state.stats.maxEnergy,
            dailyFinancials: {
                incomeShop: 0,
                incomeInventory: 0,
                incomeDungeon: 0,
                incomeRepair: 0,
                expenseMarket: 0,
                expenseWages: totalWages, // Track wages spent at end of current day (processed during rest transition)
                expenseScout: 0
            },
        },
        knownMercenaries: updatedMercenaries,
        marketStock: newMarketStock,
        unlockedTabs: newUnlockedTabs,
        forge: { ...state.forge, isShopOpen: false },
        visitorsToday: [],
        talkedToToday: [],
        activeCustomer: null,
        shopQueue: [],
        isCrafting: false,
        showSleepModal: false,
        logs: [logMsg, ...state.logs],
        forgeTemperature: 0,
        lastForgeTime: Date.now(),
    };
};

import { GameState } from '../../types/index';
import { Mercenary } from '../../models/Mercenary';
import { DUNGEON_CONFIG } from '../../config/dungeon-config';
import { PrimaryStats, mergePrimaryStats, calculateMaxHp, calculateMaxMp } from '../../models/Stats';
import { EquipmentRarity } from '../../models/Equipment';

export const handleAddKnownMercenary = (state: GameState, merc: Mercenary): GameState => {
    if (state.knownMercenaries.some(m => m.id === merc.id)) return state;
    const mercWithData = { 
        ...merc, 
        expeditionEnergy: merc.expeditionEnergy ?? DUNGEON_CONFIG.MAX_EXPEDITION_ENERGY,
        currentXp: merc.currentXp ?? 0,
        xpToNextLevel: merc.xpToNextLevel ?? (merc.level * 100),
        status: 'VISITOR' as const
    };
    return {
        ...state,
        knownMercenaries: [...state.knownMercenaries, mercWithData],
        logs: [`${merc.name} is now a regular at the tavern.`, ...state.logs]
    };
};

export const handleScoutMercenary = (state: GameState, payload: { mercenary: Mercenary; cost: number }): GameState => {
    const { mercenary, cost } = payload;
    if (state.stats.gold < cost) return state;

    const mercWithData = { 
        ...mercenary, 
        expeditionEnergy: mercenary.expeditionEnergy ?? DUNGEON_CONFIG.MAX_EXPEDITION_ENERGY,
        currentXp: mercenary.currentXp ?? 0,
        xpToNextLevel: mercenary.xpToNextLevel ?? (mercenary.level * 100),
        status: 'VISITOR' as const
    };

    return {
        ...state,
        stats: {
            ...state.stats,
            gold: state.stats.gold - cost,
            dailyFinancials: {
                ...state.stats.dailyFinancials,
                expenseScout: state.stats.dailyFinancials.expenseScout + cost
            }
        },
        knownMercenaries: [...state.knownMercenaries, mercWithData],
        logs: [`Paid ${cost} G to find new talent. ${mercenary.name} arrived at the tavern.`, ...state.logs]
    };
};

export const handleHireMercenary = (state: GameState, payload: { mercenaryId: string; cost: number }): GameState => {
    const { mercenaryId, cost } = payload;
    if (state.stats.gold < cost) return state;

    let newUnlockedTabs = [...state.unlockedTabs];
    let logUpdates: string[] = [];

    const updatedMercenaries = state.knownMercenaries.map(m => {
        if (m.id === mercenaryId) return { ...m, status: 'HIRED' as const };
        return m;
    });

    const hiredMerc = updatedMercenaries.find(m => m.id === mercenaryId);
    const name = hiredMerc ? hiredMerc.name : 'Mercenary';
    logUpdates.push(`Contract signed! ${name} has joined your service. -${cost} G`);

    if (!newUnlockedTabs.includes('DUNGEON')) {
        newUnlockedTabs.push('DUNGEON');
        logUpdates.unshift("Objective Unlocked: You can now deploy squads to explore Dungeons.");
    }

    return {
        ...state,
        stats: { 
            ...state.stats, 
            gold: state.stats.gold - cost,
            dailyFinancials: {
                ...state.stats.dailyFinancials,
                expenseScout: state.stats.dailyFinancials.expenseScout + cost
            }
        },
        knownMercenaries: updatedMercenaries,
        unlockedTabs: newUnlockedTabs,
        logs: [...logUpdates, ...state.logs]
    };
};

export const handleFireMercenary = (state: GameState, payload: { mercenaryId: string }): GameState => {
    const { mercenaryId } = payload;
    const updatedMercenaries = state.knownMercenaries.map(m => {
        if (m.id === mercenaryId) return { ...m, status: 'VISITOR' as const };
        return m;
    });
    const firedMerc = updatedMercenaries.find(m => m.id === mercenaryId);
    const name = firedMerc ? firedMerc.name : 'Mercenary';
    return {
        ...state,
        knownMercenaries: updatedMercenaries,
        logs: [`Contract terminated. ${name} is no longer in your service.`, ...state.logs]
    };
};

export const handleGiveGift = (state: GameState, payload: { mercenaryId: string; itemId: string }): GameState => {
    const { mercenaryId, itemId } = payload;
    const mercIndex = state.knownMercenaries.findIndex(m => m.id === mercenaryId);
    if (mercIndex === -1) return state;

    const inventoryItem = state.inventory.find(i => i.id === itemId);
    if (!inventoryItem || inventoryItem.quantity <= 0) return state;

    const mercenary = { ...state.knownMercenaries[mercIndex] };
    let affinityGain = 3; // Default for resources/consumables
    let staminaGain = 0;

    // Special handling for consumables
    if (itemId === 'stamina_potion') {
        staminaGain = 50;
        affinityGain = 5;
    } else if (itemId === 'affinity_debug_gift') {
        affinityGain = 50;
    } else if (inventoryItem.type === 'EQUIPMENT' && inventoryItem.equipmentData) {
        affinityGain = 5; // Base for gear
        // Rarity bonus
        switch (inventoryItem.equipmentData.rarity) {
            case EquipmentRarity.UNCOMMON: affinityGain += 2; break;
            case EquipmentRarity.RARE: affinityGain += 4; break;
            case EquipmentRarity.EPIC: affinityGain += 7; break;
            case EquipmentRarity.LEGENDARY: affinityGain += 12; break;
        }
    }

    mercenary.affinity = Math.min(100, (mercenary.affinity || 0) + affinityGain);
    if (staminaGain > 0) {
        mercenary.expeditionEnergy = Math.min(DUNGEON_CONFIG.MAX_EXPEDITION_ENERGY, (mercenary.expeditionEnergy || 0) + staminaGain);
    }

    const newInventory = state.inventory.map(item => {
        if (item.id === itemId) {
            return { ...item, quantity: item.quantity - 1 };
        }
        return item;
    }).filter(i => i.quantity > 0);

    const newMercenaries = [...state.knownMercenaries];
    newMercenaries[mercIndex] = mercenary;

    let logMsg = `Gifted ${inventoryItem.name} to ${mercenary.name}. Affinity +${affinityGain}.`;
    if (staminaGain > 0) logMsg += ` Stamina +${staminaGain}.`;

    return {
        ...state,
        inventory: newInventory,
        knownMercenaries: newMercenaries,
        logs: [logMsg, ...state.logs]
    };
};

export const handleTalkMercenary = (state: GameState, payload: { mercenaryId: string }): GameState => {
    const { mercenaryId } = payload;
    if (state.talkedToToday.includes(mercenaryId)) return state;

    const mercIndex = state.knownMercenaries.findIndex(m => m.id === mercenaryId);
    if (mercIndex === -1) return state;

    const newMercenaries = [...state.knownMercenaries];
    const merc = { ...newMercenaries[mercIndex] };
    merc.affinity = Math.min(100, (merc.affinity || 0) + 1);
    newMercenaries[mercIndex] = merc;

    return {
        ...state,
        knownMercenaries: newMercenaries,
        talkedToToday: [...state.talkedToToday, mercenaryId],
        logs: [`Talked with ${merc.name}. Affinity +1.`, ...state.logs]
    };
};

export const handleAllocateStat = (state: GameState, payload: { mercenaryId: string; stat: keyof PrimaryStats }): GameState => {
    const { mercenaryId, stat } = payload;
    const mercIndex = state.knownMercenaries.findIndex(m => m.id === mercenaryId);
    if (mercIndex === -1) return state;

    const merc = state.knownMercenaries[mercIndex];
    const totalAllocated = merc.allocatedStats.str + merc.allocatedStats.vit + merc.allocatedStats.dex + merc.allocatedStats.int + merc.allocatedStats.luk;
    const totalPossible = (merc.level - 1) * 3;

    if (totalAllocated >= totalPossible) return state;

    const newAllocated = { ...merc.allocatedStats, [stat]: merc.allocatedStats[stat] + 1 };
    const merged = mergePrimaryStats(merc.stats, newAllocated);

    // Vitals update
    const newMaxHp = calculateMaxHp(merged, merc.level);
    const newMaxMp = calculateMaxMp(merged, merc.level);
    // Heal proportional to hp increase
    const hpGain = newMaxHp - merc.maxHp;
    const mpGain = newMaxMp - merc.maxMp;

    const updatedMerc: Mercenary = {
        ...merc,
        allocatedStats: newAllocated,
        maxHp: newMaxHp,
        currentHp: merc.currentHp + (hpGain > 0 ? hpGain : 0),
        maxMp: newMaxMp,
        currentMp: merc.currentMp + (mpGain > 0 ? mpGain : 0)
    };

    const newKnownMercenaries = [...state.knownMercenaries];
    newKnownMercenaries[mercIndex] = updatedMerc;

    return {
        ...state,
        knownMercenaries: newKnownMercenaries
    };
};

export const handleUpdateMercenaryStats = (state: GameState, payload: { mercenaryId: string; stats: PrimaryStats }): GameState => {
    const { mercenaryId, stats } = payload;
    const mercIndex = state.knownMercenaries.findIndex(m => m.id === mercenaryId);
    if (mercIndex === -1) return state;

    const merc = state.knownMercenaries[mercIndex];

    const merged = mergePrimaryStats(merc.stats, stats);
    const newMaxHp = calculateMaxHp(merged, merc.level);
    const newMaxMp = calculateMaxMp(merged, merc.level);

    // Maintain current health percentage if possible, or just add the flat difference
    const hpDiff = newMaxHp - merc.maxHp;
    const mpDiff = newMaxMp - merc.maxMp;

    const updatedMerc: Mercenary = {
        ...merc,
        allocatedStats: stats,
        maxHp: newMaxHp,
        maxMp: newMaxMp,
        currentHp: merc.currentHp + (hpDiff > 0 ? hpDiff : 0),
        currentMp: merc.currentMp + (mpDiff > 0 ? mpDiff : 0)
    };

    const newKnownMercenaries = [...state.knownMercenaries];
    newKnownMercenaries[mercIndex] = updatedMerc;

    return {
        ...state,
        knownMercenaries: newKnownMercenaries,
        logs: [`Updated attributes for ${merc.name}.`, ...state.logs]
    };
};

import { GameState, InventoryItem } from '../../types/index';
import { EquipmentItem } from '../../types/inventory';
import { getEnergyCost, generateEquipment } from '../../utils/craftingLogic';
import { MATERIALS } from '../../data/materials';

// Helper for Quality Label mapping (110+ is Masterwork)
const getQualityLabel = (q: number): string => {
    if (q >= 110) return "MASTERWORK";
    if (q >= 100) return "PRISTINE";
    if (q >= 90) return "SUPERIOR";
    if (q >= 80) return "FINE";
    if (q >= 70) return "STANDARD";
    if (q >= 60) return "RUSTIC";
    return "CRUDE";
};

export const handleStartCrafting = (state: GameState, payload: { item: EquipmentItem }): GameState => {
    const { item } = payload;
    const masteryCount = state.craftingMastery[item.id] || 0;
    const energyCost = getEnergyCost(item, masteryCount);

    if (state.stats.energy < energyCost) return state;

    // Check Resources
    const hasResources = item.requirements.every(req => {
        const invItem = state.inventory.find(i => i.id === req.id);
        return invItem && invItem.quantity >= req.count;
    });
    if (!hasResources) return state;

    // Deduct Resources
    let newInventory = [...state.inventory];
    item.requirements.forEach(req => {
        newInventory = newInventory.map(invItem => {
            if (invItem.id === req.id) {
                return { ...invItem, quantity: invItem.quantity - req.count };
            }
            return invItem;
        }).filter(i => i.quantity > 0);
    });

    return {
        ...state,
        isCrafting: true,
        stats: { ...state.stats, energy: state.stats.energy - energyCost },
        inventory: newInventory,
    };
};

export const handleCancelCrafting = (state: GameState, payload: { item: EquipmentItem }): GameState => {
    const { item } = payload;
    const masteryCount = state.craftingMastery[item.id] || 0;
    const energyCost = getEnergyCost(item, masteryCount);

    // Refund Resources
    let newInventory = [...state.inventory];
    item.requirements.forEach(req => {
        const existing = newInventory.find(i => i.id === req.id);
        if (existing) {
            newInventory = newInventory.map(i => i.id === req.id ? { ...i, quantity: i.quantity + req.count } : i);
        } else {
            const itemDef = Object.values(MATERIALS).find(m => m.id === req.id);
            if (itemDef) {
                newInventory.push({ ...itemDef, quantity: req.count } as InventoryItem);
            }
        }
    });

    return {
        ...state,
        isCrafting: false,
        stats: { ...state.stats, energy: state.stats.energy + energyCost },
        inventory: newInventory,
        logs: [`Cancelled work on ${item.name}. Materials restored.`, ...state.logs]
    };
};

export const handleFinishCrafting = (state: GameState, payload: { item: EquipmentItem; quality: number; bonus?: number; masteryGain?: number }): GameState => {
    const { item, quality, bonus = 0, masteryGain = 1 } = payload;
    const masteryCount = state.craftingMastery[item.id] || 0;

    const equipment = generateEquipment(item, quality, masteryCount, bonus);
    const newInventory = [...state.inventory];

    const newItem: InventoryItem = {
        id: equipment.id, 
        name: equipment.name,
        type: 'EQUIPMENT',
        description: item.description,
        baseValue: equipment.price,
        icon: item.icon,
        quantity: 1,
        equipmentData: equipment
    };

    newInventory.push(newItem);

    const newMastery = { ...state.craftingMastery };
    newMastery[item.id] = (masteryCount || 0) + masteryGain;

    const label = getQualityLabel(quality);
    let logMsg = `Successfully crafted ${label.toLowerCase()} quality ${item.name}!`;
    if (bonus > 0) logMsg += ` Minigame technique applied a stat bonus.`;

    let newUnlockedTabs = [...state.unlockedTabs];
    if (!newUnlockedTabs.includes('INVENTORY')) {
        newUnlockedTabs.push('INVENTORY');
        logMsg = "Facility restored: Inventory tracking is now active. " + logMsg;
    }

    return {
        ...state,
        isCrafting: false,
        inventory: newInventory,
        unlockedTabs: newUnlockedTabs,
        craftingMastery: newMastery,
        lastCraftedItem: newItem,
        logs: [logMsg, ...state.logs]
    };
};

export const handleSetCrafting = (state: GameState, isCrafting: boolean): GameState => {
    return { ...state, isCrafting };
};

export const handleUpdateForgeStatus = (state: GameState, payload: { temp: number }): GameState => {
    return {
        ...state,
        forgeTemperature: payload.temp,
        lastForgeTime: Date.now()
    };
};

import { InventoryItem } from './inventory';
import { GameEvent } from './events';
import { ShopCustomer } from './shop';
import { Mercenary } from '../models/Mercenary';
import { Expedition } from '../models/Dungeon';

export type RoomType = 'EMPTY' | 'ENTRANCE' | 'BOSS' | 'KEY' | 'WALL' | 'NPC' | 'GOLD' | 'TRAP';

export interface ManualDungeonSession {
    dungeonId: string;
    partyIds: string[];
    grid: RoomType[][];
    visited: boolean[][]; // Fog of war
    playerPos: { x: number, y: number };
    hasKey: boolean;
    isBossLocked: boolean;
    isBossDefeated?: boolean; // New: Tracks if boss was beaten but player is still inside
    npcFound?: boolean; // Track if the NPC in this session was interacted with
    rescuedNpcId?: string; // ID of the NPC rescued during this session
    goldCollected: number; // Cumulative gold found during this session
}

export interface DailyFinancials {
  incomeShop: number;
  incomeInventory: number;
  incomeDungeon: number;
  incomeRepair: number;
  expenseMarket: number;
  expenseWages: number;
  expenseScout: number;
}

export interface PlayerStats {
  gold: number;
  energy: number;
  maxEnergy: number;
  day: number;
  tierLevel: number; // Current crafting/market tier access
  dailyFinancials: DailyFinancials; // Track detailed financial history for the current day
}

export interface ForgeStatus {
  hasFurnace: boolean;
  hasWorkbench: boolean;
  anvilLevel: number;
  isShopOpen: boolean;
}

export interface DungeonResult {
    dungeonName: string;
    rewards: { id: string; name: string; count: number }[];
    goldGained?: number;
    mercenaryResults: {
        id: string;
        name: string;
        job: string;
        levelBefore: number;
        levelAfter: number;
        xpGained: number;
        currentXp: number;
        xpToNext: number;
    }[];
    rescuedMercenary?: Mercenary; // Rescued NPC to be displayed in the result
}

export interface GameToast {
    message: string;
    visible: boolean;
}

export interface GameState {
  stats: PlayerStats;
  inventory: InventoryItem[];
  forge: ForgeStatus;
  activeEvent: GameEvent | null;
  logs: string[]; // For showing history of actions
  knownMercenaries: Mercenary[]; // Tracked regulars and named NPCs

  // Shop System State
  activeCustomer: ShopCustomer | null; // The person currently at the counter
  shopQueue: ShopCustomer[]; // People waiting in line
  visitorsToday: string[]; // List of Mercenary IDs who have visited today
  talkedToToday: string[]; // List of Mercenary IDs who have been talked to today for affinity bonus

  // Market State
  marketStock: Record<string, number>; // Remaining quantity per item ID

  // Game Logic Control
  isCrafting: boolean; // Is the player currently in the minigame?
  showSleepModal: boolean; // Should the End of Day modal be visible?
  showJournal: boolean; // Toggle for the Log/Journal Modal
  toast: GameToast | null; // Global toast notifications

  // Progression
  craftingMastery: Record<string, number>; // Key: Item ID, Value: Craft Count
  unlockedRecipes: string[]; // List of IDs for recipes discovered via gameplay
  unlockedTabs: string[]; // List of unlocked Tab IDs (e.g. 'FORGE', 'MARKET', 'SHOP')
  tutorialHighlight: string | null; // ID of the tab to highlight for tutorial purposes

  // Minigame Persistence
  forgeTemperature: number; // Residual heat from last session
  lastForgeTime: number; // Timestamp of last minigame interaction

  // Dungeon System
  activeExpeditions: Expedition[];
  dungeonClearCounts: Record<string, number>; // Key: Dungeon ID, Value: Count
  dungeonResult: DungeonResult | null; // Populated when claim is clicked to show modal
  activeManualDungeon: ManualDungeonSession | null; // Current manual play session
