import React, { useState, useRef, useEffect, useCallback, useLayoutEffect } from 'react';
import Header from './Header';
import { InventoryDisplay } from './InventoryDisplay';
import { Anvil, Package, ShoppingBag, Coins, Beer, Map as MapIcon, Activity, Info, ChevronLeft, ChevronRight, Pointer, Lock as LockIcon } from 'lucide-react';
import { useGame } from '../context/GameContext';

// Import Background Services
import { useShopService } from '../services/shop/shop-service';
import { useDungeonService } from '../services/dungeon/dungeon-service';

// Import Tabs
import ForgeTab from './tabs/Forge/ForgeTab';
import ShopTab from './tabs/Shop/ShopTab';
import TavernTab from './tabs/Tavern/TavernTab';
import MarketTab from './tabs/Market/MarketTab';
import DungeonTab from './tabs/Dungeon/DungeonTab';
import SimulationTab from './tabs/Simulation/SimulationTab';

// Import Modals
import EventModal from './modals/EventModal';
import SleepModal from './modals/SleepModal';
import JournalModal from './modals/JournalModal';
import DungeonResultModal from './modals/DungeonResultModal';
import CraftingResultModal from './modals/CraftingResultModal';
import SettingsModal from './modals/SettingsModal';

interface MainGameLayoutProps {
    onQuit: () => void;
    onLoadFromSettings: (data: any, index: number) => void;
}

const MainGameLayout: React.FC<MainGameLayoutProps> = ({ onQuit, onLoadFromSettings }) => {
  const [activeTab, setActiveTab] = useState<'FORGE' | 'INVENTORY' | 'MARKET' | 'SHOP' | 'TAVERN' | 'DUNGEON' | 'SIMULATION'>('FORGE');
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const { state, actions } = useGame();

  // Scroll visibility logic
  const scrollRef = useRef<HTMLDivElement>(null);
  const [showLeftArrow, setShowLeftArrow] = useState(false);
  const [showRightArrow, setShowRightArrow] = useState(false);

  const updateArrows = useCallback(() => {
    if (scrollRef.current) {
      const { scrollLeft, scrollWidth, clientWidth } = scrollRef.current;
      const canScroll = scrollWidth > clientWidth + 2;
      setShowLeftArrow(canScroll && scrollLeft > 1);
      const isAtEnd = Math.ceil(scrollLeft) >= (scrollWidth - clientWidth - 2);
      setShowRightArrow(canScroll && !isAtEnd);
    }
  }, []);

  const scrollTabs = (direction: 'LEFT' | 'RIGHT') => {
    if (scrollRef.current) {
      const amount = direction === 'LEFT' ? -200 : 200;
      scrollRef.current.scrollBy({ left: amount, behavior: 'smooth' });
    }
  };

  useLayoutEffect(() => {
    const timer = setTimeout(updateArrows, 100);
    return () => clearTimeout(timer);
  }, [updateArrows, activeTab]);

  useEffect(() => {
    window.addEventListener('resize', updateArrows);
    return () => window.removeEventListener('resize', updateArrows);
  }, [updateArrows]);

  // --- BACKGROUND SERVICES ---
  useShopService();
  useDungeonService();

  const completedExpeditionsCount = state.activeExpeditions.filter(
      exp => exp.status === 'COMPLETED'
  ).length;

  const totalShopVisitors = (state.activeCustomer ? 1 : 0) + state.shopQueue.length;

  const isFullscreenOverlay = state.isCrafting || (state.activeManualDungeon && state.showManualDungeonOverlay);

  // Tab Button Helper
  const renderTabButton = (tab: { id: typeof activeTab, icon: any, label: string, badge?: number }) => {
    const { id, icon: Icon, label, badge: badgeCount } = tab;
    const isActive = activeTab === id;
    const isUnlocked = state.unlockedTabs.includes(id);
    const isHighlighted = state.tutorialHighlight === id;

    const handleTabClick = () => {
        if (!isUnlocked) {
            // Feedback for locked facilities
            let message = "This facility needs restoration.";
            if (id === 'SHOP') message = "Install a Furnace to open the Shop Counter.";
            if (id === 'INVENTORY') message = "Acquire your first material or perform repairs to track inventory.";
            if (id === 'TAVERN') message = "Rest until Day 2 to welcome travelers at the Tavern.";
            if (id === 'DUNGEON') message = "Hire a mercenary at the Tavern to explore dungeons.";

            actions.showToast(message);
            return;
        }

        if (isHighlighted) actions.setTutorialHighlight(null);
        setActiveTab(id);
    };

    return (
        <button 
            onClick={handleTabClick}
            className={`relative flex items-center gap-2 px-5 md:px-6 py-3 md:py-4 border-b-2 transition-all whitespace-nowrap snap-start shrink-0 ${
                isActive 
                ? 'border-amber-500 text-amber-500 bg-stone-800/60 z-10' 
                : 'border-transparent text-stone-500 hover:text-stone-300'
            } ${!isUnlocked ? 'grayscale opacity-40 cursor-not-allowed' : 'hover:bg-stone-800/30'} ${isHighlighted ? 'opacity-100 grayscale-0 bg-amber-500/10' : ''}`}
        >
            {/* Tutorial Highlight Pulse */}
            {isHighlighted && (
                <div className="absolute inset-0 z-0 pointer-events-none overflow-hidden">
                    <div className="absolute inset-0 bg-amber-500/20 animate-pulse"></div>
                    <div className="absolute bottom-0 left-0 w-full h-0.5 bg-amber-500 shadow-[0_0_10px_rgba(245,158,11,1)]"></div>
                </div>
            )}

            <Icon className={`w-4 h-4 md:w-5 md:h-5 z-10 ${isActive ? 'scale-110' : ''} ${isHighlighted ? 'text-amber-400 animate-bounce' : ''}`} />
            <span className={`font-bold tracking-wide text-[10px] md:text-sm uppercase z-10 ${isHighlighted ? 'text-amber-200' : ''}`}>{label}</span>

            {/* Lock Icon for dimmed tabs */}
            {!isUnlocked && !isHighlighted && (
                <LockIcon className="w-3 h-3 text-stone-600 ml-0.5" />
            )}

            {isUnlocked && badgeCount && badgeCount > 0 ? (
                <div className="absolute top-1 right-1 flex h-4 w-4 md:h-5 md:w-5 items-center justify-center rounded-full bg-red-600 text-[8px] md:text-[10px] font-black text-white shadow-lg ring-2 ring-stone-900 animate-in zoom-in z-20">
                    {badgeCount}
                </div>
            ) : null}

            {/* Tutorial Touch Hint Icon */}
            {isHighlighted && (
                <div className="absolute -top-1 -right-1 z-30 animate-in zoom-in duration-500 pointer-events-none">
                    <div className="relative">
                        <div className="absolute inset-0 bg-amber-400 blur-md rounded-full opacity-50 animate-pulse"></div>
                        <Pointer className="w-5 h-5 text-amber-400 fill-amber-500/30 rotate-[135deg] drop-shadow-[0_0_5px_rgba(0,0,0,0.8)]" />
                    </div>
                </div>
            )}
        </button>
    );
  };

  // Define all possible tabs in desired display order
  const allTabs = [
    { id: 'FORGE' as const, icon: Anvil, label: 'Forge' },
    { id: 'MARKET' as const, icon: ShoppingBag, label: 'Market' },
    { id: 'INVENTORY' as const, icon: Package, label: 'Items' },
    { id: 'SHOP' as const, icon: Coins, label: 'Shop', badge: activeTab !== 'SHOP' ? totalShopVisitors : 0 },
    { id: 'TAVERN' as const, icon: Beer, label: 'Tavern' },
    { id: 'DUNGEON' as const, icon: MapIcon, label: 'Dungeon', badge: completedExpeditionsCount },
    { id: 'SIMULATION' as const, icon: Activity, label: 'Sim' },
  ];

  return (
    <div className="h-[100dvh] w-full bg-stone-950 text-stone-200 flex flex-col overflow-hidden font-sans selection:bg-amber-500/30 animate-in fade-in duration-500 px-safe">

      {/* Top Section Wrapper */}
      <div className={`flex flex-col shrink-0 z-30 transition-all duration-500 ease-in-out ${isFullscreenOverlay ? '-translate-y-full h-0 opacity-0 pointer-events-none' : 'translate-y-0 h-auto opacity-100'}`}>
        <Header 
          activeTab={activeTab} 
          onTabChange={setActiveTab} 
          onSettingsClick={() => setIsSettingsOpen(true)}
        />

        {/* Tab Navigation Wrapper */}
        <div className="bg-stone-900 border-b border-stone-800 flex items-center relative z-10 overflow-hidden isolate h-11 md:h-14">

          <div 
            className={`absolute left-0 top-0 bottom-0 z-30 w-12 flex items-center transition-all duration-300 transform-gpu ${
                showLeftArrow ? 'opacity-100 scale-100 visible pointer-events-auto' : 'opacity-0 scale-0 invisible pointer-events-none'
            }`}
          >
              <div className="absolute inset-0 bg-gradient-to-r from-stone-900 via-stone-900/90 to-transparent" />
              <button 
                onClick={() => scrollTabs('LEFT')}
                className="relative h-full w-full flex items-center pl-2 group/arrow"
              >
                <ChevronLeft className="w-5 h-5 text-amber-500 group-hover:scale-125 transition-transform drop-shadow-[0_0_8px_rgba(245,158,11,0.5)]" />
              </button>
          </div>

          <div 
            ref={scrollRef}
            onScroll={updateArrows}
            className="flex overflow-x-auto no-scrollbar flex-1 min-w-0 touch-pan-x scroll-smooth snap-x snap-mandatory overscroll-behavior-x-contain"
            style={{ WebkitOverflowScrolling: 'touch' }}
          >
            {allTabs.map(tab => renderTabButton(tab))}
          </div>

          <div 
            className={`absolute right-0 top-0 bottom-0 z-30 w-12 flex items-center justify-end transition-all duration-300 transform-gpu ${
                showRightArrow ? 'opacity-100 scale-100 visible pointer-events-auto' : 'opacity-0 scale-0 invisible pointer-events-none'
            }`}
          >
              <div className="absolute inset-0 bg-gradient-to-l from-stone-900 via-stone-900/90 to-transparent" />
              <button 
                onClick={() => scrollTabs('RIGHT')}
                className="relative h-full w-full flex items-center justify-end pr-2 group/arrow"
              >
                <ChevronRight className="w-5 h-5 text-amber-500 group-hover:scale-125 transition-transform drop-shadow-[0_0_8px_rgba(245,158,11,0.5)]" />
              </button>
          </div>
        </div>
      </div>

      <main className="flex-1 overflow-hidden relative bg-stone-925 flex flex-col min-h-0">
        <div className={`h-full w-full ${activeTab === 'FORGE' ? 'block' : 'hidden'}`}>
            <ForgeTab onNavigate={setActiveTab} />
        </div>
        <div className={`h-full w-full ${activeTab === 'SHOP' ? 'block' : 'hidden'}`}>
            <ShopTab onNavigate={setActiveTab} />
        </div>
        <div className={`h-full w-full ${activeTab === 'INVENTORY' ? 'block' : 'hidden'}`}>
            <InventoryDisplay />
        </div>
        <div className={`h-full w-full ${activeTab === 'MARKET' ? 'block' : 'hidden'}`}>
            <MarketTab onNavigate={setActiveTab} />
        </div>
        <div className={`h-full w-full ${activeTab === 'TAVERN' ? 'block' : 'hidden'}`}>
            <TavernTab />
        </div>
        <div className={`h-full w-full ${activeTab === 'DUNGEON' ? 'block' : 'hidden'}`}>
            <DungeonTab />
        </div>
        <div className={`h-full w-full ${activeTab === 'SIMULATION' ? 'block' : 'hidden'}`}>
            <SimulationTab />
        </div>
      </main>

      {/* Toast Notification Container */}
      {state.toast?.visible && (
        <div 
            onClick={actions.hideToast}
            className="fixed bottom-8 left-1/2 -translate-x-1/2 z-[3000] flex items-center gap-3 px-6 py-3 bg-stone-900/95 border border-amber-500/50 text-stone-200 rounded-xl shadow-2xl backdrop-blur-md cursor-pointer animate-in slide-in-from-bottom-4 fade-in duration-300 ring-2 ring-black/50 active:scale-95 w-max max-w-[80vw]"
        >
            <Info className="w-5 h-5 text-amber-500 shrink-0" />
            <span className="text-sm font-bold tracking-tight text-center leading-tight">{state.toast.message}</span>
        </div>
      )}

      <div className="h-[env(safe-area-inset-bottom)] bg-stone-900 shrink-0"></div>

      <EventModal />
      <SleepModal />
      <JournalModal />
      <DungeonResultModal />
      <CraftingResultModal />
      <SettingsModal 
        isOpen={isSettingsOpen} 
        onClose={() => setIsSettingsOpen(false)} 
        onQuit={onQuit} 
        onLoadRequest={onLoadFromSettings}
      />
    </div>
  );
};

export default MainGameLayout;

import { InventoryItem } from './inventory';
import { GameEvent } from './events';
import { ShopCustomer } from './shop';
import { Mercenary } from '../models/Mercenary';
import { Expedition } from '../models/Dungeon';

export type RoomType = 'EMPTY' | 'ENTRANCE' | 'BOSS' | 'KEY' | 'WALL' | 'NPC' | 'GOLD' | 'TRAP';

export interface ManualDungeonSession {
    dungeonId: string;
    partyIds: string[];
    grid: RoomType[][];
    visited: boolean[][]; // Fog of war
    playerPos: { x: number, y: number };
    hasKey: boolean;
    isBossLocked: boolean;
    isBossDefeated?: boolean; // New: Tracks if boss was beaten but player is still inside
    npcFound?: boolean; // Track if the NPC in this session was interacted with
    rescuedNpcId?: string; // ID of the NPC rescued during this session
    goldCollected: number; // Cumulative gold found during this session
}

export interface DailyFinancials {
  incomeShop: number;
  incomeInventory: number;
  incomeDungeon: number;
  incomeRepair: number;
  expenseMarket: number;
  expenseWages: number;
  expenseScout: number;
}

export interface PlayerStats {
  gold: number;
  energy: number;
  maxEnergy: number;
  day: number;
  tierLevel: number; // Current crafting/market tier access
  dailyFinancials: DailyFinancials; // Track detailed financial history for the current day
}

export interface ForgeStatus {
  hasFurnace: boolean;
  hasWorkbench: boolean;
  anvilLevel: number;
  isShopOpen: boolean;
}

export interface DungeonResult {
    dungeonName: string;
    rewards: { id: string; name: string; count: number }[];
    goldGained?: number;
    mercenaryResults: {
        id: string;
        name: string;
        job: string;
        levelBefore: number;
        levelAfter: number;
        xpGained: number;
        currentXp: number;
        xpToNext: number;
    }[];
    rescuedMercenary?: Mercenary; // Rescued NPC to be displayed in the result
}

export interface GameToast {
    message: string;
    visible: boolean;
}

export interface GameState {
  stats: PlayerStats;
  inventory: InventoryItem[];
  forge: ForgeStatus;
  activeEvent: GameEvent | null;
  logs: string[]; // For showing history of actions
  knownMercenaries: Mercenary[]; // Tracked regulars and named NPCs

  // Shop System State
  activeCustomer: ShopCustomer | null; // The person currently at the counter
  shopQueue: ShopCustomer[]; // People waiting in line
  visitorsToday: string[]; // List of Mercenary IDs who have visited today
  talkedToToday: string[]; // List of Mercenary IDs who have been talked to today for affinity bonus

  // Market State
  marketStock: Record<string, number>; // Remaining quantity per item ID

  // Game Logic Control
  isCrafting: boolean; // Is the player currently in the minigame?
  showSleepModal: boolean; // Should the End of Day modal be visible?
  showJournal: boolean; // Toggle for the Log/Journal Modal
  toast: GameToast | null; // Global toast notifications

  // Progression
  craftingMastery: Record<string, number>; // Key: Item ID, Value: Craft Count
  unlockedRecipes: string[]; // List of IDs for recipes discovered via gameplay
  unlockedTabs: string[]; // List of unlocked Tab IDs (e.g. 'FORGE', 'MARKET', 'SHOP')

  // Tutorial System
  tutorialStep: 'MARKET_GUIDE' | null;

  // Minigame Persistence
  forgeTemperature: number; // Residual heat from last session
  lastForgeTime: number; // Timestamp of last minigame interaction

  // Dungeon System
  activeExpeditions: Expedition[];
  dungeonClearCounts: Record<string, number>; // Key: Dungeon ID, Value: Count
  dungeonResult: DungeonResult | null; // Populated when claim is clicked to show modal
  activeManualDungeon: ManualDungeonSession | null; // Current manual play session
  showManualDungeonOverlay: boolean; // Toggle for dungeon UI visibility

  // Result Tracking
  lastCraftedItem: InventoryItem | null;

  // UI Effects State
  uiEffects: {
    energyHighlight: boolean;
  };
}

import { GameState, InventoryItem } from '../types/index';
import { NAMED_MERCENARIES } from '../data/mercenaries';
import { MATERIALS } from '../data/materials';
import { MARKET_CATALOG } from '../data/market/index';
import { DUNGEON_CONFIG } from '../config/dungeon-config';

const createInitialInventory = (): InventoryItem[] => [
    { ...MATERIALS.ANVIL, type: 'TOOL', quantity: 1 },
    { ...MATERIALS.HAMMER, type: 'TOOL', quantity: 1 },
    // Starter Materials
    { ...MATERIALS.CHARCOAL, quantity: 5 },
    { ...MATERIALS.COPPER_ORE, quantity: 2 },
    { ...MATERIALS.TIN_ORE, quantity: 1 },
    { ...MATERIALS.OAK_LOG, quantity: 1 },
    { ...MATERIALS.EMERGENCY_GOLD, quantity: 1 },
];

export const createInitialGameState = (): GameState => ({
    stats: {
        gold: 1500,
        energy: 100,
        maxEnergy: 100,
        day: 1,
        tierLevel: 0,
        dailyFinancials: {
            incomeShop: 0,
            incomeInventory: 0,
            incomeDungeon: 0,
            incomeRepair: 0,
            expenseMarket: 0,
            expenseWages: 0,
            expenseScout: 0
        },
    },
    inventory: createInitialInventory(),
    forge: {
        hasFurnace: false,
        hasWorkbench: false,
        anvilLevel: 1,
        isShopOpen: false,
    },
    activeEvent: null,
    logs: ['You stand amidst the ruins of Lockhart\'s Forge.', 'The equipment is cold and broken. You need to gather gold to rebuild.'],
    knownMercenaries: [...NAMED_MERCENARIES].map(m => ({
        ...m,
        expeditionEnergy: DUNGEON_CONFIG.MAX_EXPEDITION_ENERGY,
        currentXp: 0,
        xpToNext: m.level * 100,
        status: 'VISITOR'
    })),

    // Shop State
    activeCustomer: null,
    shopQueue: [],
    visitorsToday: [],
    talkedToToday: [],

    // Market Initial Stock
    marketStock: MARKET_CATALOG.reduce((acc, item) => ({ ...acc, [item.id]: item.maxStock }), {}),

    // Game Logic State
    isCrafting: false,
    showSleepModal: false,
    showJournal: false,
    toast: null,

    // Progression
    craftingMastery: {},
    unlockedRecipes: [],
    unlockedTabs: ['FORGE', 'MARKET'],
    tutorialStep: null,

    // Minigame Persistence
    forgeTemperature: 0,
    lastForgeTime: 0,

    // Dungeon System
    activeExpeditions: [],
    dungeonClearCounts: {},
    dungeonResult: null,
    activeManualDungeon: null,
    showManualDungeonOverlay: false,

    // Result Tracking
    lastCraftedItem: null,

    // UI Effects State
    uiEffects: {
        energyHighlight: false
    }
});

