    };

    return (
        <div className="fixed inset-0 z-[100] bg-stone-950 flex flex-col items-center justify-center animate-in fade-in duration-1000">
            {/* Background Image: forge_ruined_bg.png */}
            <div className="absolute inset-0 z-0">
                <img 
                    src={getAssetUrl('forge_ruined_bg.png')} 
