import React, { useState, useEffect } from 'react';
import { useGame } from '../../../context/GameContext';
import DialogueBox from '../../DialogueBox';
import { getAssetUrl } from '../../../utils';

const TutorialScene: React.FC = () => {
    const { actions } = useGame();
    const [currentStep, setCurrentStep] = useState(0);

    const script = [
        { text: "I have just returned from the hill after burying my family... My hands, stained with earth, are still trembling." },
        { text: "The forge has been ruthlessly trampled by their hands. Everything I built... gone in a single night of fire and blood." },
        { text: "But the fury within me burns hotter than any flame. For the sake of vengeance, I will rekindle the embers of this forge once more." },
        { text: "Wait... the furnace is completely beyond repair. I cannot melt ore without a steady flame." },
        { text: "I must head to the Market immediately to find a replacement. The hammer of the Lockhart lineage will not be silenced." }
    ];

    const handleNext = () => {
        if (currentStep < script.length - 1) {
            setCurrentStep(prev => prev + 1);
        } else {
            actions.completePrologue();
        }
    };

    return (
        <div className="fixed inset-0 z-[100] bg-stone-950 overflow-hidden animate-in fade-in duration-1000">
            {/* Background Layer: Matches TitleScreen's fitting logic with user's structure */}
            <div className="absolute inset-0 z-0 pointer-events-none bg-stone-950">
                <img 
                    src={getAssetUrl('forge_ruined_bg.png')} 
                    alt="Ruined Forge" 
                    className="w-full h-full object-cover object-center opacity-60 scale-105"
                    onError={(e) => {
                        e.currentTarget.style.display = 'none';
                        e.currentTarget.parentElement!.style.background = 'radial-gradient(circle at center, #292524 0%, #0c0a09 100%)';
                    }}
                />

                {/* Overlays to hide edges and enhance text readability */}
                <div className="absolute inset-0 bg-gradient-to-t from-black via-black/40 to-transparent"></div>
                <div className="absolute inset-0 bg-stone-950/20 backdrop-blur-[1px]"></div>
            </div>

            {/* Atmosphere Effects: Ash fall simulation */}
            <div className="absolute inset-0 pointer-events-none z-10">
                <div className="w-full h-full opacity-30 animate-pulse bg-amber-900/5"></div>
                <div className="absolute inset-0 overflow-hidden">
                   <div 
                        className="absolute top-0 left-0 w-full h-[200%] opacity-15" 
                        style={{ 
                            backgroundImage: 'radial-gradient(circle, #fff 1px, transparent 1px)', 
                            backgroundSize: '100px 100px',
                            animation: 'ash-fall 35s linear infinite'
                        }}
                    ></div>
                </div>
            </div>

            {/* Dialogue Box: Standardized layout following Shop/Tavern specs */}
            <div className="absolute bottom-6 md:bottom-12 left-1/2 -translate-x-1/2 w-[92vw] md:w-[85vw] max-w-5xl z-50 flex flex-col items-center pointer-events-none">
                <DialogueBox 
                    speaker="Lockhart"
                    text={script[currentStep].text}
                    highlightTerm={currentStep >= 3 ? "furnace" : undefined}
                    options={[
                        { label: currentStep === script.length - 1 ? "Head to Market" : "Continue", action: handleNext, variant: 'primary' }
                    ]}
                    className="w-full relative pointer-events-auto shadow-[0_0_80px_rgba(0,0,0,1)]"
                />
            </div>

            <style>{`
                @keyframes ash-fall {
                    from { transform: translateY(-50%); }
                    to { transform: translateY(0%); }
                }
            `}</style>
        </div>
    );
};

export default TutorialScene;

import { GameState } from './game-state';
import { EquipmentItem, EquipmentSlotType } from './inventory';
import { ShopCustomer } from './shop';
import { Mercenary } from '../models/Mercenary';
import { PrimaryStats } from '../models/Stats';
import { GameEvent } from './events';

export interface GameContextType {
  state: GameState;
  actions: {
    repairItem: () => void;
    rest: () => void;
    confirmSleep: () => void;
    closeRest: () => void;
    triggerEvent: (event: GameEvent) => void;
    handleEventOption: (action: () => void) => void;
    closeEvent: () => void;

    saveGame: (slotIndex?: number) => void;
    loadGame: (loadedState: GameState) => void;

    startCrafting: (item: EquipmentItem) => void;
    cancelCrafting: (item: EquipmentItem) => void;
    finishCrafting: (item: EquipmentItem, quality: number, bonus?: number, masteryGain?: number) => void;
    craftItem: (item: EquipmentItem, quality: number) => void; 
    dismissCraftingResult: () => void;

    buyItems: (items: { id: string; count: number }[], totalCost: number) => void;
    sellItem: (itemId: string, count: number, price: number, equipmentInstanceId?: string, customer?: Mercenary) => void;
    toggleShop: () => void;
    addMercenary: (merc: Mercenary) => void;
    scoutMercenary: (merc: Mercenary, cost: number) => void;
    consumeItem: (id: string, count: number) => void;

    enqueueCustomer: (customer: ShopCustomer) => void;
    nextCustomer: () => void;
    dismissCustomer: () => void;

    setCrafting: (isCrafting: boolean) => void;
    updateForgeStatus: (temp: number) => void;
    toggleJournal: () => void;

    hireMercenary: (mercenaryId: string, cost: number) => void;
    fireMercenary: (mercenaryId: string) => void;
    giveGift: (mercenaryId: string, itemId: string) => void;
    talkMercenary: (mercenaryId: string) => void;

    startExpedition: (dungeonId: string, partyIds: string[]) => void;
    completeExpedition: (expeditionId: string) => void;
    // Added missing abortExpedition method definition
    abortExpedition: (expeditionId: string) => void;
    claimExpedition: (expeditionId: string) => void;
    dismissDungeonResult: () => void;

    equipItem: (mercenaryId: string, inventoryItemId: string) => void;
    unequipItem: (mercenaryId: string, slot: EquipmentSlotType) => void;

    useItem: (itemId: string) => void;
    allocateStat: (mercenaryId: string, stat: keyof PrimaryStats) => void;
    updateMercenaryStats: (mercenaryId: string, stats: PrimaryStats) => void;

    triggerEnergyHighlight: () => void;
    showToast: (message: string) => void;
    hideToast: () => void;

    setTutorialStep: (step: GameState['tutorialStep']) => void;
    // Added missing completePrologue action
    completePrologue: () => void;

    // Manual Dungeon Actions
    startManualAssault: (dungeonId: string, partyIds: string[]) => void;
    moveInManualDungeon: (dx: number, dy: number) => void;
    finishManualAssault: () => void;
    retreatFromManualDungeon: () => void;
    toggleManualDungeonOverlay: (show: boolean) => void;
    rescueMercenary: (npcId: string) => void;
  };
}

import React, { useState, useEffect } from 'react';
import { useGame } from '../../../context/GameContext';
import DialogueBox from '../../DialogueBox';
import { getAssetUrl } from '../../../utils';

const TutorialScene: React.FC = () => {
    const { actions } = useGame();
    const [isStarted, setIsStarted] = useState(false);
    const [currentStep, setCurrentStep] = useState(0);

    const script = [
        { text: "I have just returned from the hill after burying my family... My hands, stained with earth, are still trembling." },
        { text: "The forge has been ruthlessly trampled by their hands. Everything I built... gone in a single night of fire and blood." },
        { text: "But the fury within me burns hotter than any flame. For the sake of vengeance, I will rekindle the embers of this forge once more." },
        { text: "Wait... the furnace is completely beyond repair. I cannot melt ore without a steady flame." },
        { text: "I must head to the Market immediately to find a replacement. The hammer of the Lockhart lineage will not be silenced." }
    ];

    const handleNext = () => {
        if (currentStep < script.length - 1) {
            setCurrentStep(prev => prev + 1);
        } else {
            actions.completePrologue();
        }
    };

    const startTutorial = () => {
        if (!isStarted) {
            setIsStarted(true);
        }
    };

    return (
        <div 
            className="fixed inset-0 z-[100] bg-stone-950 overflow-hidden animate-in fade-in duration-1000 flex flex-col items-center justify-center cursor-pointer"
            onClick={startTutorial}
        >
            {/* Background Layer: Matches TitleScreen's fitting logic */}
            <div className="absolute inset-0 z-0 pointer-events-none bg-stone-950">
                <img 
                    src={getAssetUrl('forge_ruined_bg.png')} 
                    alt="Ruined Forge" 
                    className="w-full h-full object-cover object-center opacity-60 scale-105"
                    onError={(e) => {
                        e.currentTarget.style.display = 'none';
                        e.currentTarget.parentElement!.style.background = 'radial-gradient(circle at center, #292524 0%, #0c0a09 100%)';
                    }}
                />

                {/* Overlays: Gradient removed as requested. Keeping subtle dust/blur for depth. */}
                <div className="absolute inset-0 bg-stone-950/20 backdrop-blur-[1px]"></div>
            </div>

            {/* Atmosphere Effects: Ash fall simulation */}
            <div className="absolute inset-0 pointer-events-none z-10">
                <div className="w-full h-full opacity-30 animate-pulse bg-amber-900/5"></div>
                <div className="absolute inset-0 overflow-hidden">
                   <div 
                        className="absolute top-0 left-0 w-full h-[200%] opacity-15" 
                        style={{ 
                            backgroundImage: 'radial-gradient(circle, #fff 1px, transparent 1px)', 
                            backgroundSize: '100px 100px',
                            animation: 'ash-fall 35s linear infinite'
                        }}
                    ></div>
                </div>
            </div>

            {/* Start Prompt: Visible only before the first interaction */}
            {!isStarted && (
                <div className="relative z-20 flex flex-col items-center animate-pulse">
                    <span className="text-stone-500 font-black uppercase tracking-[0.4em] text-[10px] md:text-sm">Tap to Begin</span>
                </div>
            )}

            {/* Dialogue Box: Standardized layout following Shop/Tavern specs */}
            {isStarted && (
                <div className="absolute bottom-6 md:bottom-12 left-1/2 -translate-x-1/2 w-[92vw] md:w-[85vw] max-w-5xl z-50 flex flex-col items-center pointer-events-none">
                    <DialogueBox 
                        speaker="Lockhart"
                        text={script[currentStep].text}
                        highlightTerm={currentStep >= 3 ? "furnace" : undefined}
                        options={[
                            { label: currentStep === script.length - 1 ? "Head to Market" : "Continue", action: handleNext, variant: 'primary' }
                        ]}
                        className="w-full relative pointer-events-auto shadow-[0_0_100px_rgba(0,0,0,1)]"
                    />
                </div>
            )}

            <style>{`
                @keyframes ash-fall {
                    from { transform: translateY(-50%); }
                    to { transform: translateY(0%); }
                }
            `}</style>
        </div>
    );
};

export default TutorialScene;
